import Foundation

protocol HeroInvestingProviding {
    var score: Int { get }          // 0~100 integer; view에서 clamp(0, 100)
    var oneLiner: String { get }    // 큰 본문 한줄 카피
    var displayDate: Date { get }   // 날짜 라벨 원본 값
}

struct MockHeroInvestingProvider: HeroInvestingProviding {
    var score: Int
    var oneLiner: String
    var displayDate: Date

    init(
        score: Int = 72,
        oneLiner: String = "공격보다 관찰이 내 성향에 맞아요",
        displayDate: Date = {
            var comps = DateComponents()
            comps.year = 2026
            comps.month = 4
            comps.day = 23
            return Calendar.current.date(from: comps) ?? Date()
        }()
    ) {
        self.score = score
        self.oneLiner = oneLiner
        self.displayDate = displayDate
    }
}

import SwiftUI

struct InsightCard {
    let badgeLabel: String      // 예: "금기"
    let badgeColor: Color       // DesignTokens 토큰 참조
    let icon: String            // SF Symbol name
    let title: String           // bold 제목
    let desc: String            // 멀티라인; \n 포함 가능
    let bottomLabel: String     // 하단 캡션, 예: "오늘의 금기"
}

protocol InsightsProviding {
    var cards: [InsightCard] { get }   // 뷰는 인덱스 0=금기, 1=일진, 2=실천 고정 매핑
}

struct MockInsightsProvider: InsightsProviding {
    var cards: [InsightCard] {
        [
            InsightCard(
                badgeLabel: "금기",
                badgeColor: DesignTokens.tabooColor,
                icon: "exclamationmark.triangle",
                title: "큰 거래 자제",
                desc: "오늘은 큰 거래보다\n작은 수익에 집중하세요",
                bottomLabel: "오늘의 금기"
            ),
            InsightCard(
                badgeLabel: "일진",
                badgeColor: DesignTokens.todayColor,
                icon: "sun.max",
                title: "목(木)의 기운",
                desc: "목의 기운이 강한 날로\n새로운 시작에 좋아요",
                bottomLabel: "오늘의 일진"
            ),
            InsightCard(
                badgeLabel: "실천",
                badgeColor: DesignTokens.practiceColor,
                icon: "checkmark.circle",
                title: "리밸런싱 점검",
                desc: "포트폴리오를 점검하고\n목표 비중을 재조정하세요",
                bottomLabel: "오늘의 실천"
            ),
        ]
    }

    init() {}
}

import SwiftUI

// Cached date formatter for Hero date label (DateFormatter creation is expensive)
private let heroDateFormatter: DateFormatter = {
    let f = DateFormatter()
    f.dateFormat = "yyyy.MM.dd EEEE"
    f.locale = Locale(identifier: "ko_KR")
    return f
}()

/// Clamps a hero score to the 0–100 valid range.
/// Declared internal so unit tests can access it via @testable import.
func clampHeroScore(_ score: Int) -> Int {
    min(max(0, score), 100)
}

struct HeroInvestingCardView: View {
    let provider: any HeroInvestingProviding
    let userProfile: any UserProfileProviding
    let onTap: () -> Void

    private var clampedScore: Int {
        clampHeroScore(provider.score)
    }

    private var formattedDate: String {
        heroDateFormatter.string(from: provider.displayDate)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            // 날짜 라벨
            Text(formattedDate)
                .font(.caption)
                .foregroundStyle(DesignTokens.muted)
                .accessibilityIdentifier("HomeHeroDate")

            // 인사말
            Text("\(userProfile.displayName)님, 오늘의 투자 태도예요")
                .font(.subheadline)
                .accessibilityIdentifier("HomeHeroGreeting")

            // 카드 전체를 Button으로 감싸서 단일 hit-test 보장
            Button(action: onTap) {
                VStack(alignment: .leading, spacing: 12) {
                    // 투자 관점 배지 pill
                    Text("투자 관점")
                        .font(.caption2)
                        .padding(.horizontal, 8)
                        .padding(.vertical, 4)
                        .background(DesignTokens.line3)
                        .clipShape(Capsule())

                    // 원형 지수 + /100
                    HStack(alignment: .firstTextBaseline, spacing: 2) {
                        Text("\(clampedScore)")
                            .font(.system(size: 48, weight: .bold))
                            .accessibilityIdentifier("HomeHeroScore")
                        Text("/100")
                            .font(.title3)
                            .foregroundStyle(DesignTokens.muted)
                    }
                    .accessibilityLabel("\(clampedScore)점")

                    // 한줄 카피
                    Text(provider.oneLiner)
                        .font(.body)
                        .fixedSize(horizontal: false, vertical: true)
                        .accessibilityIdentifier("HomeHeroOneLiner")

                    HStack {
                        Spacer()
                        Text("상세 보기 ›")
                            .font(.caption)
                            .foregroundStyle(DesignTokens.muted)
                    }
                }
                .padding(16)
                .background(DesignTokens.gray)
                .clipShape(RoundedRectangle(cornerRadius: 12))
                .contentShape(Rectangle())
            }
            .buttonStyle(.plain)
            .accessibilityIdentifier("HomeHeroCard")
        }
        .padding(.horizontal, 16)
        .padding(.top, 16)
    }
}

import SwiftUI

// MARK: - Single Insight Card

struct InsightCardView: View {
    let card: InsightCard
    let onTap: () -> Void

    var body: some View {
        Button(action: onTap) {
            VStack(alignment: .leading, spacing: 8) {
                // 상단 badge pill
                Text(card.badgeLabel)
                    .font(.caption2)
                    .foregroundStyle(.white)
                    .padding(.horizontal, 8)
                    .padding(.vertical, 4)
                    .background(card.badgeColor)
                    .clipShape(Capsule())

                // 아이콘 (large)
                Image(systemName: card.icon)
                    .font(.system(size: 36))
                    .foregroundStyle(card.badgeColor)

                // title bold
                Text(card.title)
                    .font(.headline)
                    .fixedSize(horizontal: false, vertical: true)

                // desc multiline (\n 유지)
                Text(card.desc)
                    .font(.caption)
                    .foregroundStyle(DesignTokens.muted)
                    .fixedSize(horizontal: false, vertical: true)

                Spacer(minLength: 4)

                // 하단 캡션
                Text(card.bottomLabel)
                    .font(.caption2)
                    .foregroundStyle(DesignTokens.muted)
            }
            .padding(12)
            .frame(width: 160)
            .background(DesignTokens.gray)
            .clipShape(RoundedRectangle(cornerRadius: 12))
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .accessibilityLabel("\(card.badgeLabel), \(card.title)")
    }
}

// MARK: - Empty Placeholder Card (AC-14)

private struct InsightPlaceholderCard: View {
    let index: Int

    var body: some View {
        RoundedRectangle(cornerRadius: 12)
            .fill(DesignTokens.gray)
            .frame(width: 160, height: 200)
            .accessibilityIdentifier("InsightCard_empty_\(index)")
    }
}

// MARK: - Insights Horizontal Scroll View

struct InsightsScrollView: View {
    let provider: any InsightsProviding
    let onTabooTap: () -> Void
    let onTodayTap: () -> Void
    let onPracticeTap: () -> Void

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text("오늘의 인사이트")
                .font(.headline)
                .padding(.horizontal, 16)
                .accessibilityIdentifier("HomeInsightsSectionLabel")

            ScrollView(.horizontal, showsIndicators: false) {
                HStack(spacing: 8) {
                    // 슬롯 0: 금기 (고정 순서)
                    if let card = provider.cards[safe: 0] {
                        InsightCardView(card: card, onTap: onTabooTap)
                            .accessibilityIdentifier("HomeInsightsCard_0")
                    } else {
                        InsightPlaceholderCard(index: 0)
                    }

                    // 슬롯 1: 일진 (고정 순서)
                    if let card = provider.cards[safe: 1] {
                        InsightCardView(card: card, onTap: onTodayTap)
                            .accessibilityIdentifier("HomeInsightsCard_1")
                    } else {
                        InsightPlaceholderCard(index: 1)
                    }

                    // 슬롯 2: 실천 (고정 순서)
                    if let card = provider.cards[safe: 2] {
                        InsightCardView(card: card, onTap: onPracticeTap)
                            .accessibilityIdentifier("HomeInsightsCard_2")
                    } else {
                        InsightPlaceholderCard(index: 2)
                    }
                }
                .padding(.horizontal, 16)
            }
        }
        .padding(.top, 16)
    }
}

import Foundation

extension Collection {
    /// Returns the element at the given index if it is within bounds, otherwise nil.
    subscript(safe index: Index) -> Element? {
        indices.contains(index) ? self[index] : nil
    }
}

